function escMd(s) { return String(s).replace(/([_*`\[])/g, '\\$1'); }

const data = $input.all().map(item => item.json);
const payload = data[0];
const stories = payload.stories || [];
const weekArticleCount = payload.weekArticleCount || 0;

let text;

if (stories.length === 0) {
  text = '📡 *Bias Radar — Weekly Blind Spots*\n\nNo significant coverage gaps found this week.';
} else {
  const lines = [
    '📡 *Bias Radar — What Got Missed This Week*',
    `_Analyzed ${weekArticleCount} headlines from your feed_`,
    ''
  ];

  stories.forEach((story, index) => {
    lines.push(`*${index + 1}. ${escMd(story.story)}*`);
    lines.push(`Why underreported: ${escMd(story.whyUnderreported)}`);
    lines.push(`❓ ${escMd(story.questionToAsk)}`);
    if (index < stories.length - 1) {
      lines.push('');
    }
  });

  lines.push('');
  lines.push('_Bias Radar · The Daily Brief_');

  text = lines.join('\n');
}

return [{ json: { text } }];
